function BaseIconNew:DoApply()
    if not self:IsInstant() then
        self:StartLoadIcon()
    else
        self:ApplyIconUI()
    end
end

function BaseIconNew:StartLoadIcon()

    if self._isLoading then
        return
    end
    self._isLoading = true

    local args = self._iconArgs
    if self._bUsePool then
        GF.MakeItemASyncFromGamePool(LPoolTagConst.TAG_ICON_CACHE, args, function(go, args)
            self._isLoading = false
            self:OnPoolIconInstEnd(go, args)
        end)
    else
        local assetPath = args:GetItemPath()
        if self._resRequester then
            self._resRequester:Dispose()
            self._resRequester = nil
        end
        local resRequester = LxResUtil.GetAssetRequester(assetPath, typeofGameObject, function(obj)
            self._isLoading = false
            self:OnIconLoaded(obj)
        end)
        self._resRequester = resRequester
        resRequester:StartRequester()
    end
end

function BaseIconNew:OnPoolIconInstEnd(instantTrans, args)
    if CS.IsNullObject(instantTrans) then
        return
    end
    local parentTrans = self._parentTrans
    if self:IsDestroy() or not parentTrans or not CS.IsValidObject(parentTrans) then
        GF.ReturnItemToGamePool(LPoolTagConst.TAG_ICON_CACHE, args:GetItemKey(), instantTrans)
        return
    end
    self:SetIconInst(instantTrans.transform)
end

function BaseIconNew:OnIconLoaded(asset, assetName, bundleName)
    if not asset then return end

    self._bundleName = bundleName
    local parentTrans = self._parentTrans
    if self:IsDestroy() or not parentTrans or not CS.IsValidObject(parentTrans) then
        if not self._bUsePool then
        end
        return
    end

    local instantGo = LxResUtil.NewObject(asset)
    instantGo.name = self._iconArgs:GetItemName()
    asset = nil

    self:SetIconInst(instantGo.transform)
end
