function BaseIconNew:Destroy()
    if self:IsDestroy() then
        return
    end

    if self._resRequester then
        self._resRequester:Dispose()
        self._resRequester = nil
    end

    self:OnDestroy()
    self:DestroyTime()

    if self:IsIconValid() then
        local iconInst = self._iconInst
        local bRelease = false
        if CS.IsValidObject(self._uiIconComp) then
            local sprite = self._uiIconComp.sprite
            self._uiIconComp.sprite = nil
            sprite = nil
            bRelease = true
        end

        local bReturnOk = false
        if self._bUsePool then
            bReturnOk = GF.ReturnItemToGamePool(LPoolTagConst.TAG_ICON_CACHE, self._iconArgs:GetItemKey(), iconInst)
        elseif not bRelease and CS.IsValidObject(iconInst) then
            LxResUtil.DestroyObject(iconInst.gameObject)
        end
    end

    self:ClearClick()

    local args = self._iconArgs
    LxNodeBase.Dispose(self)
    self._iconArgs = args
    self._isDestroy = true
end

