function BaseIconNew:InitTrans()
    self._uiIconBgTrans = CS.FindTrans(self._iconInst, "IconBg")
    self._uiIconTrans = CS.FindTrans(self._uiIconBgTrans, "Icon")
    if not self._uiIconTrans then
        self._uiIconTrans = CS.FindTrans(self._iconInst, "Icon")
    end

    self._uiIconComp = self._uiIconTrans:GetComponent(typeUIImage)
    self._uiIconBgComp = self._uiIconBgTrans:GetComponent(typeUIImage)

    if self._isIconHideInPosition then
        self:UpdateHideInPosition()
    elseif self._localPos then
        self:SetAnchoredPosition(self._localPos)
    end

    self:OnInitTrans()
end

