function BaseIconNew:InitStartList()
    self._cacheStar = 0
    local uiStartList = {}
    self._startList = uiStartList
    if self._ownerWndClass and CS.IsValidObject(self._uiComStarTrans) then
        self._ownerWndClass:SetComStar(self._uiComStarTrans, 0, true)
    else
        for index = 1, 20 do
            local starTrans = CS.FindTrans(self._uiStarTrans, "Star" .. index)
            if starTrans then
                uiStartList[index] = starTrans
                if starTrans.gameObject.activeSelf then
                    CS.ShowObject(starTrans, false)
                end
            end
        end
    end
end

function BaseIconNew:UpdateStarUI()
    local cacheStar = self._cacheStar
    local star = self._displayStar

    if self._ownerWndClass and CS.IsValidObject(self._uiComStarTrans) then
        self._ownerWndClass:SetComStar(self._uiComStarTrans, star, true,false,self:IsRhombusIcon())
        return
    end

    local uiStartList = self._startList
    self._cacheStar = star
    local img, temp, index = LUtil.GetHeroStarImg(star)
    local cacheImg, cacheTemp, cacheIndex = LUtil.GetHeroStarImg(cacheStar)
    local limitMin = index * 5 - 5
    local limitMax = math.min(index * 5, star)
    local oldLimitMin = cacheIndex * 5 - 5
    local oldLimitMax = math.min(cacheIndex * 5, cacheStar)
    for k = 1, #uiStartList do
        -->10则全部灭掉采用新的逻辑
        if star > 10 then
            CS.ShowObject(uiStartList[k], false)
        else
            --旧的显示着的 判断要不要显示  -- 10 的采用新的逻辑
            if k > oldLimitMin and k <= oldLimitMax then
                --不在新的显示范围内 不显示
                if k <= limitMin or k > limitMax then
                    CS.ShowObject(uiStartList[k], false)
                end
            elseif k > limitMin and k <= limitMax then
                --不在旧的显示范围内，显示
                if k <= oldLimitMin or k > oldLimitMax then
                    CS.ShowObject(uiStartList[k], true)
                end
            end
        end
    end
    --star >10 用新的显示逻辑
    if star > 10 then
        CS.ShowObject(self._uiHightStarTrans, true)
        CS.ShowObject(self._uiStarTrans, false)

        self:SetXUIText(self._uiHightStarText, star - 10, nil, nil)
    else
        CS.ShowObject(self._uiHightStarTrans, false)
        CS.ShowObject(self._uiStarTrans, true)
    end
end

