function BaseIconNew:SetIcon(imgPath)
    if imgPath == self._iconPath then
        return
    end

    self._iconPath = imgPath

    if not self:IsIconValid() then
        return
    end

    self:UpdateIcon()
end

function BaseIconNew:UpdateIcon()
    local imgPath = self._iconPath

    if not self._uiIconTrans.gameObject.activeSelf then
        CS.ShowObject(self._uiIconTrans, true)
    end

    if string.isempty(imgPath) then
        return
    end

    if self._ownerWndClass then

        local isNativeSize = true
        if self._isNativeSize ~= nil then
            isNativeSize = self._isNativeSize
        end

        -- 放在窗体里加载，方便做关联释放
        self:SetImage(self._uiIconTrans, imgPath, function()
            if self:IsDestroy() then
                if CS.IsValidObject(self._uiIconComp) then
                else
                end
                return
            end

            if self._uiIconTrans and CS.IsValidObject(self._uiIconTrans) and not self._uiIconTrans.gameObject.activeSelf then
                CS.ShowObject(self._uiIconTrans, true)
            end
            LxUiHelper.SetImageAlpha(self._uiIconTrans, 1)
        end, isNativeSize, true, self._defaultIconName)
    else
        self:SetImage(self._uiIconTrans, imgPath, function()
            if self:IsDestroy() then
                if CS.IsValidObject(self._uiIconComp) then
                else
                end
                return
            end

            if self._uiIconTrans and CS.IsValidObject(self._uiIconTrans) and not self._uiIconTrans.gameObject.activeSelf then
                CS.ShowObject(self._uiIconTrans, true)
            end
            LxUiHelper.SetImageAlpha(self._uiIconTrans, 1)
        end, true, true, self._defaultIconName)
    end

end

function BaseIconNew:SetIconBg(imgPath)
    if imgPath == self._iconBgPath then
        return
    end
    self._iconBgPath = imgPath
    if not self:IsIconValid() then
        return
    end
    self:UpdateIconBg()
end



function BaseIconNew:UpdateIconBg()
    local imgPath = self._iconBgPath
    if string.isempty(imgPath) then return end

    if self._ownerWndClass then
        -- 放在窗体里加载，方便做关联释放
        self._ownerWndClass:SetWndEasyImage(self._uiIconBgTrans, imgPath, nil, true, false, nil, self._defaultIconName)
    else
        self:SetImage(self._uiIconBgTrans, imgPath, nil, false, false, self._defaultIconName)
    end
end

