function BaseIconNew:SetXUIText(xuiTextTrans, msg, size, color)
    local xuiText = self:FindXUIText(xuiTextTrans)
    if CS.IsNullObject(xuiText) then
        return
    end

    self:SetXTextContent(xuiTextTrans, msg)

    local fontSize = size or self._fontSize
    if fontSize then
        xuiText.fontSize = fontSize
    end
    local fontColor = color or self._fontColor
    if fontColor then
        xuiText.color = fontColor
    end
end

