        -- 放在窗体里加载，方便做关联释放
        self._ownerWndClass:SetWndEasyImage(trans, imgPath, func, isNativeSize, false, nil, self._defaultIconName)
    else
        self:SetImage(trans, imgPath, func, isNativeSize, false, self._defaultIconName)
    end
end

function BaseIconNew:CreateIconEffect(info)
    if self._ownerWndClass then
        local effName = info.effName
        if not effName then
            return
        end

        local trans = info.trans
        if CS.IsNullObject(trans) then
            return
        end

        local effKey = info.effKey or trans:GetInstanceID()
        local scaleSize = info.scaleSize or 100
        local bDefaultLayer = info.bDefaultLayer
        local bDefaultSorting = info.bDefaultSorting
        local bDefaultSortNum = info.bDefaultSortNum
        local preloadCallback = info.preloadCallback
        local scaleSizeY = info.scaleSizeY
        local addMask = info.addMask
        local sortLayer = info.sortLayer
        local endFunc = info.endFunc
        local upSortOrder = info.upSortOrder
        self._ownerWndClass:CreateWndEffect(trans, effName, effKey, scaleSize, bDefaultLayer, bDefaultSorting, bDefaultSortNum, preloadCallback, scaleSizeY, addMask, sortLayer, endFunc, upSortOrder)
    end
end

