function BaseIconNew:EnableHideInPos(bHide)
    self._isIconHideInPosition = bHide
    if not self:IsIconValid() then
        return
    end
    self:UpdateHideInPosition()
end

function BaseIconNew:UpdateHideInPosition()
    if self._isIconHideInPosition then
        self._iconInst.transform.localPosition = Vector3(10000, 10000, 0)
    else
        if self._localPos then
            self._iconInst.transform.anchoredPosition = self._localPos
        else
            self._iconInst.transform.localPosition = Vector3.zero
        end
    end
end

