function BaseIconNew:GetItemQualityRefByStarLv(starLv)

    local retRef
    for k = 1, 7 do
        local ref = GameTable.RarityRef[k]
        if ref then
            if starLv <= ref.heroStarQuality then
                retRef = ref
                break
            end
        end
    end
    return retRef
end

