function BaseIconNew:TimerStop(key)
    if self._baseIconTimer then
        self._baseIconTimer:TimerRemoveByKey(key)
    end
end

----@param timeScale = false:不受加速 影响，true：受加速 影响
function BaseIconNew:TimerStart(key, time, timeScale, loopCnt)
    local timeUnscale = not timeScale
    if not (self._baseIconTimer or self:IsDestroy()) then
        self._baseIconTimer = LxTimer:New()
    end

    if self._baseIconTimer then
        self._baseIconTimer:TimerCreate(key, function(...)
            self:OnTryTimer(...)
        end, time, timeUnscale, loopCnt)
    end
end

function BaseIconNew:OnTryTimer(key)
    if (self.OnTimer) then
        self:OnTimer(key)
    end
end

function BaseIconNew:IsTimeExist(key)
    if not self._baseIconTimer then
        return false
    end
    local time = self._baseIconTimer:TimerGetByKey(key)
    return time ~= nil
end

function BaseIconNew:TimePauseAll(bPause)
    if self._baseIconTimer then
        self._baseIconTimer:TimerPause(bPause)
    end
end

function BaseIconNew:DestroyTime()
    local baseIconTimer = self._baseIconTimer
    if baseIconTimer then
        baseIconTimer:Destroy()
        self._baseIconTimer = nil
    end
end

return BaseIconNew